from ..utils.logs import log

# Global recorder instance
_recorder: Optional[McpRecorder] = None
_recording_enabled: bool = False


def get_recorder() -> Optional[McpRecorder]:
    """Get the current recorder instance."""
    global _recorder
    return _recorder


def start_recording() -> McpRecorder:
    """Start recording tool calls."""
    global _recorder, _recording_enabled
    _recorder = McpRecorder()
    _recording_enabled = True
    log.info(f"Started recording session: {_recorder.session.session_id}")
    return _recorder


def stop_recording() -> Optional[ToolCallSession]:
    """Stop recording and return the session."""
    global _recorder, _recording_enabled
    _recording_enabled = False
    if _recorder:
        session = _recorder.session
        log.info(f"Stopped recording. Total calls: {len(session.calls)}")
        return session
    return None


def is_recording() -> bool:
    """Check if recording is enabled."""
    return _recording_enabled


def record_call(tool_name: str, args: Dict[str, Any], result: Any, duration_ms: float, success: bool, error: Optional[str] = None) -> None:
    """Record a tool call if recording is enabled."""
    global _recorder
    if _recording_enabled and _recorder:
        call = ToolCall(
            tool_name=tool_name,
            args=args,
            result=result if isinstance(result, dict) else {"value": str(result)},
            duration_ms=duration_ms,
            success=success,
            error=error
        )
        _recorder.session.add(call)

# %% ../../nbs/99_tests/01_agent_e2e.ipynb #327e3472
def enable_auto_recording(mcp) -> None:
    """Patch MCP to automatically record all tool calls when recording is enabled.
    
    Call this after creating the MCP but before running it.
    """
    original_call_tool = mcp.call_tool
    
    async def recording_call_tool(name: str, arguments: dict) -> Any:
        start_time = time.time()
        error_msg = None
        success = True
        result = None
        
        try:
            result = await original_call_tool(name, arguments)
            # Check if result indicates failure
            if isinstance(result, dict) and result.get("ok") is False:
                success = False
                error_msg = result.get("error", "Unknown error")
        except Exception as e:
            success = False
            error_msg = str(e)
            raise
        finally:
            duration_ms = (time.time() - start_time) * 1000
            # Record the call
            record_call(
                tool_name=name,
                args=arguments,
                result=result,
                duration_ms=duration_ms,
                success=success,
                error=error_msg
            )
        
        return result
    
    mcp.call_tool = recording_call_tool
    log.info("Auto-recording enabled for MCP tool calls")

