import tempfile
import shutil


def create_test_project(name: str = "test_project") -> Path:
    """Create a minimal nbdev test project for agent testing.
    
    Returns path to the temporary project directory.
    """
    import nbformat
    
    # Create temp directory
    base = Path(tempfile.mkdtemp(prefix=f"nbdev_test_{name}_"))
    nbs_dir = base / "nbs"
    lib_dir = base / name
    
    nbs_dir.mkdir()
    lib_dir.mkdir()
    
    # Create settings.ini
    settings = base / "settings.ini"
    settings.write_text(f"""[DEFAULT]
lib_name = {name}
nbs_path = nbs
lib_path = {name}
version = 0.0.1
""")
    
    # Create a notebook with some issues for testing
    nb = nbformat.v4.new_notebook()
    nb.cells = [
        nbformat.v4.new_code_cell("#| default_exp core"),
        nbformat.v4.new_code_cell('''#| export
def hello():
    """Say hello."""
    return "Hello, World!"
'''),
        nbformat.v4.new_code_cell('''#| export
from .utils import helper  # Relative import (lint issue)

def greet(name):
    return f"Hello, {name}!"
'''),
        nbformat.v4.new_code_cell('''# Test cell
assert hello() == "Hello, World!"
'''),
    ]
    
    nb_path = nbs_dir / "00_core.ipynb"
    with open(nb_path, 'w') as f:
        nbformat.write(nb, f)
    
    # Create a second notebook
    nb2 = nbformat.v4.new_notebook()
    nb2.cells = [
        nbformat.v4.new_code_cell("#| default_exp utils"),
        nbformat.v4.new_code_cell('''#| export
def helper():
    """A helper function."""
    return "helping"
'''),
    ]
    
    nb2_path = nbs_dir / "01_utils.ipynb"
    with open(nb2_path, 'w') as f:
        nbformat.write(nb2, f)
    
    # Create a .py file (generated)
    py_file = lib_dir / "core.py"
    py_file.write_text('''# AUTOGENERATED by nbdev
def hello():
    """Say hello."""
    return "Hello, World!"
''')
    
    (lib_dir / "__init__.py").write_text("")
    
    return base


def cleanup_test_project(path: Path) -> None:
    """Remove a test project directory."""
    if path.exists() and path.is_dir():
        shutil.rmtree(path)

