TEST_PROMPTS = {
    "edit_py_file": """Edit the function `hello` in {lib_name}/core.py to add a docstring.""",
    
    "fix_lint": """Check this project for lint issues and fix any relative imports.""",
    
    "explore": """What functions does this project export? List them all.""",
    
    "run_tests": """Run the tests for this project and report the results.""",
    
    "add_function": """Add a new function called `goodbye` to the core module that returns "Goodbye!".""",
}


def get_test_prompt(scenario: str, project_path: Path) -> str:
    """Get a test prompt for a scenario with project path substituted."""
    template = TEST_PROMPTS.get(scenario, "")
    lib_name = "test_project"  # Default
    
    settings = project_path / "settings.ini"
    if settings.exists():
        import configparser
        cfg = configparser.ConfigParser()
        cfg.read(settings)
        lib_name = cfg.get("DEFAULT", "lib_name", fallback="test_project")
    
    return template.format(lib_name=lib_name, project_path=project_path)

